sys_security_acl.script:
if (gs.hasRole('x_2097092_linq.platform_admin')) {
  answer = true;
} else if (gs.hasRole('x_2097092_linq.college_admin')) {
  // College admin reads events of their college
  var userCollege = gs.getUser().getRecord().getValue('u_college');
  answer = (current.getValue('college') == userCollege);
} else if (gs.hasRole('x_2097092_linq.club_admin') || gs.hasRole('x_2097092_linq.club_member')) {
  // club_admin/club_member: read events of clubs they belong to
  var gr = new GlideRecord('x_2097092_linq_club_membership');
  gr.addQuery('member', gs.getUserID());
  gr.addQuery('club', current.getValue('club'));
  gr.addQuery('status', 'active');
  gr.query();
  if (gr.hasNext()) {
    answer = true;
  } else {
    // Also allow if it is a live event they can see as student
    var status = current.getValue('status');
    if (status == 'live') {
      var scope = current.getValue('college_scope');
      if (scope == 'inter_college') {
        answer = true;
      } else {
        var studentCollege = gs.getUser().getRecord().getValue('u_college');
        answer = (current.getValue('college') == studentCollege);
      }
    } else {
      answer = false;
    }
  }
} else {
  // Students: read only live events filtered by college scope
  var eventStatus = current.getValue('status');
  if (eventStatus == 'live') {
    var eventScope = current.getValue('college_scope');
    if (eventScope == 'inter_college') {
      // Inter-college events visible to all verified students
      answer = true;
    } else {
      // College-only events filtered by user's college
      var stuCollege = gs.getUser().getRecord().getValue('u_college');
      answer = (current.getValue('college') == stuCollege);
    }
  } else {
    answer = false;
  }
}
